 17→package com.ichi2.anki
 18→
 19→import android.os.Bundle
 20→import android.view.View
 21→import com.ichi2.anim.ActivityTransitionAnimation
 22→import com.ichi2.anki.UIUtils.showThemedToast
 23→import com.ichi2.anki.cardviewer.PreviewLayout
 24→import com.ichi2.anki.cardviewer.PreviewLayout.Companion.createAndDisplay
