 43→object NoteService {
 44→    /**
 45→     * Creates an empty Note from given Model
 46→     *
 47→     * @param model the model in JSOBObject format
 48→     * @return a new note instance
 49→     */
 50→    fun createEmptyNote(model: JSONObject): MultimediaEditableNote? {
 51→        try {
 52→            val fieldsArray = model.getJSONArray("flds")
 53→            val numOfFields = fieldsArray.length()
 54→            if (numOfFields > 0) {
 55→                val note = MultimediaEditableNote()
 56→                note.setNumFields(numOfFields)
 57→                for (i in 0 until numOfFields) {
 58→                    val fieldObject = fieldsArray.getJSONObject(i)
 59→                    val uiTextField = TextField()
 60→                    uiTextField.name = fieldObject.getString("name")
 61→                    uiTextField.text = fieldObject.getString("name")
 62→                    note.setField(i, uiTextField)
 63→                }
 64→                note.modelId = model.getLong("id")
 65→                return note
 66→            }
 67→        } catch (e: JSONException) {
 68→            // TODO Auto-generated catch block
 69→            Timber.w(e)
 70→        }
 71→        return null
 72→    }
