 74→    fun updateMultimediaNoteFromFields(col: com.ichi2.libanki.Collection, fields: Array<String>, modelId: NoteTypeId, mmNote: MultimediaEditableNote) {
 75→        for (i in fields.indices) {
 76→            val value = fields[i]
 77→            val field: IField = if (value.startsWith("<img")) {
 78→                ImageField()
 79→            } else if (value.startsWith("[sound:") && value.contains("rec")) {
 80→                AudioRecordingField()
 81→            } else if (value.startsWith("[sound:")) {
 82→                MediaClipField()
 83→            } else {
 84→                TextField()
 85→            }
 86→            field.setFormattedString(col, value)
 87→            mmNote.setField(i, field)
 88→        }
 89→        mmNote.modelId = modelId
 90→        mmNote.freezeInitialFieldValues()
 91→        // TODO: set current id of the note as well
 92→    }
