 94→    /**
 95→     * Updates the JsonNote field values from MultimediaEditableNote When both notes are using the same Model, it updates
 96→     * the destination field values with source values. If models are different it throws an Exception
 97→     *
 98→     * @param noteSrc
 99→     * @param editorNoteDst
100→     */
101→    fun updateJsonNoteFromMultimediaNote(noteSrc: IMultimediaEditableNote?, editorNoteDst: Note) {
102→        if (noteSrc is MultimediaEditableNote) {
103→            if (noteSrc.modelId != editorNoteDst.mid) {
104→                throw RuntimeException("Source and Destination Note ID do not match.")
105→            }
106→            val totalFields: Int = noteSrc.numberOfFields
107→            for (i in 0 until totalFields) {
108→                editorNoteDst.values()[i] = noteSrc.getField(i)!!.formattedValue!!
109→            }
110→        }
111→    }
