114→     * Considering the field is new, if it has media handle it
115→     *
116→     * @param field
117→     */
118→    fun importMediaToDirectory(col: com.ichi2.libanki.Collection, field: IField?) {
119→        var tmpMediaPath: String? = null
120→        when (field!!.type) {
121→            EFieldType.AUDIO_RECORDING, EFieldType.MEDIA_CLIP -> tmpMediaPath = field.audioPath
122→            EFieldType.IMAGE -> tmpMediaPath = field.imagePath
123→            EFieldType.TEXT -> {
124→            }
125→        }
126→        if (tmpMediaPath != null) {
127→            try {
128→                val inFile = File(tmpMediaPath)
129→                if (inFile.exists() && inFile.length() > 0) {
130→                    val fname = col.media.addFile(inFile)
131→                    val outFile = File(col.media.dir, fname)
132→                    Timber.v("""File "%s" should be copied to "%s""", fname, outFile)
133→                    if (field.hasTemporaryMedia && outFile.absolutePath != tmpMediaPath) {
134→                        // Delete original
135→                        inFile.delete()
136→                    }
137→                    when (field.type) {
138→                        EFieldType.AUDIO_RECORDING, EFieldType.MEDIA_CLIP -> field.audioPath = outFile.absolutePath
139→                        EFieldType.IMAGE -> field.imagePath = outFile.absolutePath
140→                        else -> {
141→                        }
142→                    }
143→                }
144→            } catch (e: IOException) {
145→                throw RuntimeException(e)
146→            } catch (mediaException: EmptyMediaException) {
147→                // This shouldn't happen, but we're fine to ignore it if it does.
148→                Timber.w(mediaException)
149→                CrashReportService.sendExceptionReport(mediaException, "noteService::importMediaToDirectory")
150→            }
151→        }
152→    }
