155→     * @param replaceNewlines Converts [FieldEditText.NEW_LINE] to HTML linebreaks
156→     */
157→    @VisibleForTesting
158→    @CheckResult
159→    fun getFieldsAsBundleForPreview(editFields: Collection<NoteField?>?, replaceNewlines: Boolean): Bundle {
160→        val fields = Bundle()
161→        // Save the content of all the note fields. We use the field's ord as the key to
162→        // easily map the fields correctly later.
163→        if (editFields == null) {
164→            return fields
165→        }
166→        for (e in editFields) {
167→            if (e?.fieldText == null) {
168→                continue
169→            }
170→            val fieldValue = convertToHtmlNewline(e.fieldText!!, replaceNewlines)
171→            fields.putString(e.ord.toString(), fieldValue)
172→        }
173→        return fields
174→    }
