176→    fun convertToHtmlNewline(fieldData: String, replaceNewlines: Boolean): String {
177→        return if (!replaceNewlines) {
178→            fieldData
179→        } else {
180→            fieldData.replace(FieldEditText.NEW_LINE, "<br>")
181→        }
