183→    /** When the next template is requested  */
184→    fun onNextCard() {
185→        var index = cardIndex
186→        if (!isNextBtnEnabled(index)) {
187→            return
188→        }
189→        cardIndex = ++index
190→        onCardIndexChanged()
191→    }
192→
193→    /** When the previous template is requested  */
194→    fun onPreviousCard() {
195→        var index = cardIndex
196→        if (!isPrevBtnEnabled(index)) {
197→            return
198→        }
199→        cardIndex = --index
200→        onCardIndexChanged()
201→    }
202→
203→    /**
204→     * Loads the next card after the current card index has been changed
205→     */
206→    private fun onCardIndexChanged() {
207→        val prevBtnEnabled = isPrevBtnEnabled(cardIndex)
208→        val nextBtnEnabled = isNextBtnEnabled(cardIndex)
209→        Timber.d("onCardIndexChanged: index=$cardIndex, prev=$prevBtnEnabled, next=$nextBtnEnabled")
210→        previewLayout!!.setPrevButtonEnabled(prevBtnEnabled)
211→        previewLayout!!.setNextButtonEnabled(nextBtnEnabled)
212→        setCurrentCardFromNoteEditorBundle(getColUnsafe)
213→        displayCardQuestion()
214→    }
215→
216→    private fun isPrevBtnEnabled(cardIndex: Int): Boolean {
217→        return cardIndex > 0
218→    }
219→
220→    private fun isNextBtnEnabled(cardIndex: Int): Boolean {
221→        return cardIndex < cardCount - 1
222→    }
