224→    public override fun onSaveInstanceState(outState: Bundle) {
225→        outState.putString(CardTemplateNotetype.INTENT_MODEL_FILENAME, mEditedModelFileName)
226→        outState.putLongArray("cardList", mCardList)
227→        outState.putInt("ordinal", mOrdinal)
228→        outState.putInt("cardListIndex", mCardListIndex)
229→        outState.putBundle("noteEditorBundle", mNoteEditorBundle)
230→        outState.putBoolean("showingAnswer", mShowingAnswer)
231→        super.onSaveInstanceState(outState)
232→    }
233→
234→    override fun onCollectionLoaded(col: Collection) {
235→        super.onCollectionLoaded(col)
236→        if (mNoteEditorBundle != null) {
237→            mAllFieldsNull = false
238→            // loading from the note editor
239→            if (mEditedNotetype != null) {
240→                Timber.d("onCollectionLoaded: mOrdinal=$mOrdinal")
241→                val fields = getBundleEditFields(mNoteEditorBundle)
242→                val tempCard = getDummyCard(mEditedNotetype, 0, fields)
243→                if (tempCard != null) {
244→                    val note = tempCard.note()
245→                    cardIndex = if (mEditedNotetype!!.isCloze) {
246→                        val clozes = col.clozeNumbersInNote(note)
247→                        // clozes are 1-based (e.g. 1, 3). mOrdinal is 0-based ord (e.g. 0, 2).
248→                        val idx = clozes.indexOf(mOrdinal + 1)
249→                        if (idx >= 0) idx else 0
250→                    } else {
251→                        mOrdinal
252→                    }
253→                }
254→            }
255→            val toPreview = setCurrentCardFromNoteEditorBundle(col)
256→            if (toPreview != null) {
257→                cardCount = toPreview.note().numberOfCardsEphemeral()
258→                if (cardCount >= 2) {
259→                    previewLayout!!.showNavigationButtons()
260→                }
261→            }
262→        } else {
263→            // loading from the card template editor
264→            mAllFieldsNull = true
265→            // card template with associated card due to opening from note editor
266→            if (mCardList != null && mCardListIndex >= 0 && mCardListIndex < mCardList!!.size) {
267→                currentCard = PreviewerCard(col, mCardList!![mCardListIndex])
268→            } else if (mEditedNotetype != null) { // bare note type (not coming from note editor), or new card template
269→                Timber.d("onCreate() CardTemplatePreviewer started with edited model and template index, displaying blank to preview formatting")
270→                currentCard = getDummyCard(mEditedNotetype!!, mOrdinal)
271→                if (currentCard == null) {
272→                    showThemedToast(applicationContext, getString(R.string.invalid_template), false)
273→                    closeCardTemplatePreviewer()
274→                }
275→            }
276→        }
277→        if (currentCard == null) {
278→            showThemedToast(applicationContext, getString(R.string.invalid_template), false)
279→            closeCardTemplatePreviewer()
280→            return
281→        }
282→        displayCardQuestion()
283→        if (mShowingAnswer) {
284→            displayCardAnswer()
285→        }
286→        showBackIcon()
287→    }
288→
289→    protected fun getCard(col: Collection, cardListIndex: Long): Card {
290→        return PreviewerCard(col, cardListIndex)
291→    }
292→
293→    private fun setCurrentCardFromNoteEditorBundle(col: Collection): Card? {
294→        assert(mNoteEditorBundle != null)
295→        currentCard = getDummyCard(mEditedNotetype, cardIndex, getBundleEditFields(mNoteEditorBundle))
296→        // example: a basic card with no fields provided
297→        if (currentCard == null) {
298→            return null
299→        }
300→        val newDid = mNoteEditorBundle!!.getLong("did")
301→        if (col.decks.isDyn(newDid)) {
302→            currentCard!!.oDid = currentCard!!.did
303→        }
304→        currentCard!!.did = newDid
305→        val currentNote = currentCard!!.note()
306→        val tagsList = mNoteEditorBundle!!.getStringArrayList("tags")
307→        setTags(currentNote, tagsList)
308→        return currentCard
309→    }
310→
311→    /**
312→     * Set the set tags of currentNote to tagsList.  We make no
313→     * assumption on the content of tagsList, except that its strings
314→     * are valid tags (i.e. no spaces in it).
315→     */
316→    private fun setTags(currentNote: Note, tagsList: List<String>?) {
317→        val currentTags = currentNote.tags.toTypedArray()
318→        for (tag in currentTags) {
319→            currentNote.delTag(tag)
320→        }
321→        if (tagsList != null) {
322→            val tagsSet = currentNote.col.tags.canonify(tagsList)
323→            currentNote.addTags(tagsSet)
324→        }
325→    }
326→
327→    private fun getLabels(fieldValues: MutableList<String>) {
328→        if (mCardType != null && mCardType == getString(R.string.cloze_model_name)) {
329→            fieldValues[0] = getString(R.string.cloze_sample_text, "c1")
330→        }
331→        if (mCardType != null && mCardType == getString(R.string.basic_typing_model_name)) {
332→            fieldValues[1] = getString(R.string.basic_answer_sample_text)
333→        }
334→    }
335→
336→    private fun getBundleEditFields(noteEditorBundle: Bundle?): MutableList<String> {
337→        val noteFields = noteEditorBundle!!.getBundle("editFields")
338→            ?: return mutableListOf()
339→        // we map from "int" -> field, but the order isn't guaranteed, and there may be skips.
340→        // so convert this to a list of strings, with null in place of the invalid fields
341→        val elementCount = noteFields.keySet().stream().map { s: String -> s.toInt() }.max { obj: Int, anotherInteger: Int? -> obj.compareTo(anotherInteger!!) }.orElse(-1) + 1
342→        val ret = Array(elementCount) { "" } // init array, nulls cause a crash
343→        for (fieldOrd in noteFields.keySet()) {
344→            ret[fieldOrd.toInt()] = noteFields.getString(fieldOrd)!!
345→        }
346→        return mutableListOf(*ret)
347→    }
348→
349→    /**
350→     * This method generates a note from a sample model, or fails if invalid
351→     * @param index The index in the templates for the model. NOT `ord`
352→     */
353→    fun getDummyCard(notetype: NotetypeJson, index: Int): Card? {
354→        return getDummyCard(notetype, index, notetype.fieldsNames.toMutableList())
355→    }
356→
357→    /**
358→     * This method generates a note from a sample model, or fails if invalid
359→     * @param cardIndex The index in the templates for the model. NOT `ord`
360→     */
361→    private fun getDummyCard(notetype: NotetypeJson?, cardIndex: Int, fieldValues: MutableList<String>): Card? {
362→        Timber.d("getDummyCard() Creating dummy note for index %s", cardIndex)
363→        if (notetype == null) {
364→            return null
365→        }
366→        if (mAllFieldsNull) {
367→            getLabels(fieldValues)
368→        }
369→        val n = getColUnsafe.newNote(notetype)
370→        var i = 0
371→        while (i < fieldValues.size && i < n.fields.size) {
372→            if (mAllFieldsNull) {
373→                if (mCardType != null && mCardType == getString(R.string.cloze_model_name) && i == 0 ||
374→                    mCardType == getString(R.string.basic_typing_model_name) && i == 1
375→                ) {
376→                    n.setField(i, fieldValues[i])
377→                } else {
378→                    n.setField(i, "(" + fieldValues[i] + ")")
379→                }
380→            } else {
381→                n.setField(i, fieldValues[i])
382→            }
383→            i++
384→        }
385→        try {
386→            return EphemeralCard.fromNote(n, getColUnsafe, cardIndex)
387→        } catch (e: Exception) {
388→            // Calling code handles null return, so we can log this for developer's interest but move on
389→            Timber.d(e, "getDummyCard() unable to create card")
390→        }
391→        return null
392→    }
393→
394→    /** Override certain aspects of Card behavior so we may display unsaved data  */
395→    inner class PreviewerCard : Card {
396→        private val mNote: Note?
397→
398→        constructor(col: Collection, id: Long) : super(col, id) {
399→            mNote = null
400→        }
401→
402→        /* if we have an unsaved note saved, use it instead of a collection lookup */ override fun note(
403→            reload: Boolean
404→        ): Note {
405→            return mNote ?: super.note(reload)
406→        }
407→
408→        /** if we have an unsaved note saved, use it instead of a collection lookup  */
409→        override fun note(): Note {
410→            return mNote ?: super.note()
411→        }
412→
413→        /** if we have an unsaved note, never return empty  */
414→        val isEmpty: Boolean
415→            get() = mNote != null
416→
417→        /** Override the method that fetches the model so we can render unsaved models  */
418→        override fun model(): NotetypeJson {
419→            return mEditedNotetype ?: super.model()
420→        }
421→
422→        override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
423→            if (renderOutput == null || reload) {
424→                val index = if (model().isCloze) {
425→                    0
426→                } else {
427→                    ord
428→                }
429→                val context = TemplateManager.TemplateRenderContext.fromCardLayout(
430→                    note(),
431→                    this,
432→                    model(),
433→                    model().getJSONArray("tmpls")[index] as JSONObject,
434→                    fillEmpty = false
435→                )
436→                renderOutput =
437→                    context.render()
438→            }
439→            return renderOutput!!
440→        }
441→    }
442→}
443→
444→private class EphemeralCard(col: Collection, id: Long?) : Card(col, id) {
445→    override fun renderOutput(reload: Boolean, browser: Boolean): TemplateRenderOutput {
446→        return this.renderOutput!!
447→    }
448→    companion object {
449→        fun fromNote(n: Note, col: Collection, cardIndex: Int = 0): EphemeralCard {
450→            val card = EphemeralCard(col, null)
451→            card.did = 1
452→            card.ord = n.cardIndexToOrd(cardIndex)
453→
454→            val nt = n.notetype
455→            val templateIdx = if (nt.type == Consts.MODEL_CLOZE) {
456→                0
457→            } else {
458→                cardIndex
459→            }
460→            val template = nt.tmpls[templateIdx] as JSONObject
461→            template.put("ord", card.ord)
462→
463→            val output = TemplateManager.TemplateRenderContext.fromCardLayout(
464→                n,
465→                card,
466→                notetype = nt,
467→                template = template,
468→                fillEmpty = false
469→            ).render()
470→            card.renderOutput = output
471→            card.setNote(n)
472→            return card
473→        }
474→    }
475→}
476→
477→/** returns the number of cards from a note which has not had data saved in the database */
478→private fun Note.numberOfCardsEphemeral(): Int {
479→    // We can't use note.numberOfCards() as this uses the database value
480→    return when {
481→        this.notetype.isCloze -> col.clozeNumbersInNote(this).size
482→        else -> notetype.templatesNames.size
483→    }
484→}
485→
486→/**
487→ * Given a card index, returns the 'ord' of the card
488→ */
489→private fun Note.cardIndexToOrd(index: Int): Int {
490→    // We can't use note.numberOfCards() as this uses the database value
491→    return when {
492→        this.notetype.isCloze -> col.clozeNumbersInNote(this)[index] - 1
493→        else -> index
494→    }
495→}
