            if (mEditedNotetype != null) {
                if (mOrdinal > 0) {
                    val fields = getBundleEditFields(mNoteEditorBundle)
                    val tempCard = getDummyCard(mEditedNotetype, 0, fields)
                    if (tempCard != null) {
                        val note = tempCard.note()
                        cardIndex = if (mEditedNotetype!!.isCloze) {
                            val clozes = col.clozeNumbersInNote(note)
                            // clozes are 1-based (e.g. 1, 3). mOrdinal is 0-based ord (e.g. 0, 2).
                            val idx = clozes.indexOf(mOrdinal + 1)
                            if (idx >= 0) idx else 0
                        } else {
                            mOrdinal
                        }
                    }
                }
            }
            val toPreview = setCurrentCardFromNoteEditorBundle(col)
